mapper.select:
SELECT tool_id, tool_code, tool_name, description
FROM tools
WHERE tool_code = #{toolCode}

mapper.update:
UPDATE group_tool_mapping
SET is_enabled = FALSE
WHERE group_id = #{groupId}

mapper.insert:
INSERT INTO group_tool_mapping (group_id, tool_id, is_enabled)
SELECT #{groupId}, t.tool_id, #{isEnabled}
FROM tools t
WHERE t.tool_code = #{toolCode}
ON DUPLICATE KEY UPDATE is_enabled = VALUES(is_enabled)

mapper.update:
UPDATE group_tool_mapping
SET is_enabled = TRUE
WHERE group_id = #{groupId}
